<template>
  <section class="bg-blue-grey-darken-3 py-10" style="min-height: 100vh">
    <v-container>
      <v-row>
        <v-col>
          <h1 class="font-weight-bold heading" :class="data.h1">
            <span class="light_blue">Technology</span> Studied
          </h1>
          <h3 class="pt-10">
            <span class="teknologi"></span>
          </h3>
        </v-col>
      </v-row>
      <v-row>
        <v-col cols="12" class="techno">
          <v-tooltip :text="item.name" location="top" v-for="item in icon" :key="item">
            <template v-slot:activator="{ props }">
              <v-icon
                v-bind="props"
                color="#0fe"
                size="125"
                class="mx-3 my-10"
                :style="{ boxShadow: '0 0 1rem #0fe' }"
              >
                {{ item.icons }}
              </v-icon>
            </template>
          </v-tooltip>
          <v-divider class="border-opacity-0"></v-divider>
        </v-col>
      </v-row>
      <v-row class="pb-10">
        <v-col cols="6" class="express">
          <v-tooltip text="Node JS Framework" location="top">
            <template v-slot:activator="{ props }">
              <v-icon
                v-bind="props"
                color="#0fe"
                size="50"
                class="mx-3"
                :style="{ textShadow: '0 0 1rem #0fe' }"
              >
                <h6>
                  <span>Express</span>
                </h6>
              </v-icon>
            </template>
          </v-tooltip>
        </v-col>
        <v-col cols="6" class="hapi">
          <v-tooltip text="Node JS Framework" location="top">
            <template v-slot:activator="{ props }">
              <v-icon
                v-bind="props"
                color="#0fe"
                size="50"
                class="mx-3"
                :style="{ textShadow: '0 0 1rem #0fe' }"
              >
                <h6>
                  <span>Hapi</span>
                </h6>
              </v-icon>
            </template>
          </v-tooltip>
        </v-col>
      </v-row>
      <v-divider class="pt-10 align-center"></v-divider>
      <v-row>
        <v-col class="heading">
          <h1 class="pa-1 font-weight-black" :class="data.h1">Certificate</h1>
        </v-col>
      </v-row>
      <v-row class="d-flex justify-center align-center pb-15">
        <v-col
          cols="12"
          sm="6"
          md="4"
          class="d-flex justify-center align-center px-5 certificates"
          v-for="certificate in certificates"
          :key="certificate"
        >
          <v-hover v-slot="{ isHovering, props }">
            <v-card
              class="mx-auto rounded-xl"
              color="grey-lighten-4"
              max-width="400"
              max-height="250"
              v-bind="props"
              :style="isHovering ? { boxShadow: '0 0 1rem #0fe' } : null"
            >
              <v-img
                cover
                :class="isHovering ? 'zoom' : 'pa-0 '"
                :aspect-ratio="16 / 16"
                :src="certificate.image"
              >
                <v-expand-transition>
                  <div
                    v-if="isHovering"
                    class="d-flex flex-column v-card--reveal transition-in-slowly text-center w-100"
                    style="
                      height: 100%;
                      background: linear-gradient(rgba(0, 0, 0, 0.1), #0fe);
                      bottom: 0;
                      position: absolute;
                    "
                  >
                    <h6
                      class="text-white font-weight-bold pb-5 pt-15 px-5"
                      :style="{ fontSize: data.h6 }"
                    >
                      {{ certificate.name }}
                    </h6>

                    <a :href="certificate.image" target="_blank">
                      <div class="pa-2 bg-white rounded-circle d-inline-block">
                        <v-icon color="black" size="20px">mdi-open-in-new</v-icon>
                      </div>
                    </a>
                  </div>
                </v-expand-transition>
              </v-img>
            </v-card>
          </v-hover>
        </v-col>
      </v-row>
    </v-container>
  </section>
</template>
<script>
import { computed, onMounted, ref } from 'vue';
import vuetify from '@/plugins/vuetify';
import Typed from 'typed.js';
import service from '../../services/service';

export default {
  setup() {
    const icon = computed(() => [
      {
        name: 'HTML',
        icons: `mdi-language-html5`,
      },
      {
        name: 'CSS',
        icons: 'mdi-language-css3',
      },
      {
        name: 'Javascript',
        icons: 'mdi-language-javascript',
      },
      {
        name: 'Vue Js',
        icons: 'mdi-vuejs',
      },
      {
        name: 'Node Js',
        icons: 'mdi-nodejs',
      },
    ]);

    const data = computed(() => {
      if (vuetify.display.width.value < 600) {
        return {
          h1: 'text-h4',
          h6: '14px',
        };
      } else {
        return {
          h1: 'text-h4',
          h6: '16px',
        };
      }
    });

    onMounted(() => {
      const typed = new Typed('.teknologi', {
        strings: [
          'Dapat menggunakan technology',
          '<span class="light_blue">HTML, CSS, Javascript,</span> and <span class="light_blue">Node Js</span> ',
          'Javascript Framework <span class="light_blue">Vue</span> ',
          'framework Node Js <span class="light_blue">Express</span> and <span class="light_blue">Hapi.</span>',
        ],
        typeSpeed: 100,
        backSpeed: 100,
        backDelay: 1000,
        loop: true,
      });

      typed.start();
    });

    const certificates = ref();
    onMounted(async () => {
      const response = await service.getCertificates();
      certificates.value = response;
    });

    return {
      data,
      icon,
      certificates,
    };
  },
};
</script>
