<template>
  <section class="d-flex align-center" :style="{ backgroundColor: '#1f242d', minHeight: '100vh' }">
    <v-container>
      <v-row>
        <v-col>
          <h1 class="pt-15 font-weight-bold text-white heading" :class="data.h1">
            Latest <span class="light_blue">Project</span>
          </h1>
        </v-col>
      </v-row>

      <v-row class="py-10" justify="center">
        <v-col class="projects" cols="12" sm="4" md="4" v-for="project in projects" :key="project">
          <v-hover v-slot="{ isHovering, props }">
            <v-card
              class="mx-auto rounded-xl"
              color="grey-lighten-4"
              max-width="600"
              max-height="250"
              v-bind="props"
            >
              <v-img
                :class="isHovering ? 'zoom' : ''"
                :aspect-ratio="16 / 16"
                cover
                :src="project.image"
              >
                <v-expand-transition>
                  <div
                    v-if="isHovering"
                    class="d-flex flex-column v-card--reveal transition-in-slowly text-center w-100"
                    style="
                      height: 100%;
                      background: linear-gradient(rgba(0, 0, 0, 0.1), #0fe);
                      bottom: 0;
                      position: absolute;
                    "
                  >
                    <h6 class="text-white pt-15 px-5" :style="{ fontSize: data.h6 }">
                      {{ project.name }}
                    </h6>
                    <p class="px-10 text-white my-2 description" :style="{ fontSize: data.p }">
                      {{ project.description }}
                    </p>
                    <div class="pa-2 d-flex justify-center">
                      <v-btn @click="go(project.url_site)" class="rounded-pill">
                        <v-icon color="black" size="20px">mdi-open-in-new</v-icon>
                      </v-btn>
                    </div>
                  </div>
                </v-expand-transition>
              </v-img>
            </v-card>
          </v-hover>
        </v-col>
      </v-row>
    </v-container>
  </section>
</template>
<script>
import { computed, onMounted, ref } from 'vue';
import vuetify from '@/plugins/vuetify';
import service from '../../services/service';
export default {
  setup() {
    const projects = ref();
    onMounted(async () => {
      const response = await service.getProjects();
      projects.value = response;
    });
    const data = computed(() => {
      if (vuetify.display.width.value < 600) {
        return {
          h1: 'text-h4',
          h6: '18px',
          p: '14px',
          order1: 'order-1 text-center text-justify',
          order2: 'order-2 ',
          height: '300',
          flex: 'h-auto d-flex flex-column align-center ',

          overflow: 'overflow-y-auto',
        };
      } else {
        return {
          h1: 'text-h4',
          h6: '20px',
          p: '10px',
          order1: 'text-start',
          height: '400',
          flex: 'h-screen d-flex  align-center justify-center',
        };
      }
    });

    const go = (url) => {
      window.open(url, '_blank');
    };
    return {
      data,
      projects,
      go,
    };
  },
};
</script>
<style scoped>
.description {
  display: -webkit-box;
  -webkit-box-orient: vertical;
  -webkit-line-clamp: 3;
  overflow: hidden;
  text-overflow: ellipsis;
}
</style>
